#!/usr/bin/env python3
"""
Convert NLP slide citations to clickable links pointing to PDF page numbers.

Two problems being fixed:
1. The previous agent used the prof's *cumulative footer* number (e.g. "slide 220")
   as the visible slide identifier. Replace with the *PDF page* (1-N within deck).
2. Markdown links with literal spaces in paths break in Obsidian. URL-encode them.

Final form: `[slide K](url-encoded-path#page=K)` where K is the PDF page index.
"""

import re
from pathlib import Path
from urllib.parse import quote

VAULT = Path("/Users/mattporteous/Obsidian/School")

# slide-range -> (offset, filename, session_id)
# offset such that PDF_page = cumulative_footer - offset
SESSIONS = [
    (195, 214, 194, "Session 13 - Word Embeddings.pdf",          13),
    (215, 230, 214, "Session 14 - POS tagging.pdf",              14),
    (231, 249, 230, "Session 15 - NER.pdf",                      15),
    (250, 269, 249, "Session 16 - Neural Networks-1.pdf",        16),
    (270, 286, 269, "Session 17 - Recurrent NN.pdf",             17),
    (287, 307, 286, "Session 18 - Beyonf RNNs.pdf",              18),
    (308, 328, 307, "Session 19 - Transformers-1.pdf",           19),
    (329, 360, 328, "Session 24 - Challenges and futures.pdf",   24),
]

def session_for(slide_num: int):
    for lo, hi, offset, fname, sid in SESSIONS:
        if lo <= slide_num <= hi:
            return offset, fname, sid
    return None

def prefix_for(file_path: Path) -> str:
    rel = file_path.relative_to(VAULT)
    parts = rel.parts
    if parts[0] == "10-Courses" and parts[2] == "lectures":
        return "../../30-Sources/NLP/pdf/"
    if parts[0] == "20-Concepts":
        return "../30-Sources/NLP/pdf/"
    if parts[0] == "40-Reviews" and "flashcards" in parts:
        return "../../../30-Sources/NLP/pdf/"
    return None

def url_encode_filename(fname: str) -> str:
    # Encode the filename only — keep #page= fragment as-is.
    return quote(fname)

def make_link(visible: str, prefix: str, fname: str, page: int) -> str:
    return f"[{visible}]({prefix}{url_encode_filename(fname)}#page={page})"

# In-scope files: only NLP material that touches Sessions 13-19, 24.
# We discover them by globbing and then filtering by content.
TARGET_GLOBS = [
    "10-Courses/NLP/lectures/lecture-13-*.md",
    "10-Courses/NLP/lectures/lecture-14-*.md",
    "10-Courses/NLP/lectures/lecture-15-*.md",
    "10-Courses/NLP/lectures/lecture-16-*.md",
    "10-Courses/NLP/lectures/lecture-17-*.md",
    "10-Courses/NLP/lectures/lecture-18-*.md",
    "10-Courses/NLP/lectures/lecture-19-*.md",
    "10-Courses/NLP/lectures/lecture-24-*.md",
    "40-Reviews/NLP/flashcards/lecture-13.md",
    "40-Reviews/NLP/flashcards/lecture-14.md",
    "40-Reviews/NLP/flashcards/lecture-15.md",
    "40-Reviews/NLP/flashcards/lecture-16.md",
    "40-Reviews/NLP/flashcards/lecture-17.md",
    "40-Reviews/NLP/flashcards/lecture-18.md",
    "40-Reviews/NLP/flashcards/lecture-19.md",
    "40-Reviews/NLP/flashcards/lecture-24.md",
    "20-Concepts/*.md",   # filter below
]

def file_in_scope(path: Path) -> bool:
    """Concept notes are in scope if they reference any Session 13-19/24 content."""
    if "20-Concepts" not in str(path):
        return True
    text = path.read_text()
    # Touch only files that mention Session 13-19 or Session 24 (in front-matter or cites)
    return bool(re.search(r"Session (1[3-9]|24)\b", text))

def collect_files() -> list[Path]:
    seen = set()
    for pattern in TARGET_GLOBS:
        for p in VAULT.glob(pattern):
            if p.is_file() and p not in seen:
                if file_in_scope(p):
                    seen.add(p)
    return sorted(seen)

# Patterns, applied in order on each line:
# 1. Existing clickable: [slide N](.../Session ... .pdf#page=K)
#    → keep page=K as-is, set visible to "slide K", URL-encode the path.
EXISTING_LINK_RE = re.compile(
    r"\[slide(s?) ([\d–\-]+)\]"
    r"\(([^)]*?Session[^)]*?\.pdf)#page=(\d+)\)"
)

# 2. Bare cumulative-footer cite: (slide N) or (slides N–M) — convert.
BARE_CITE_RE = re.compile(
    r"(?<!\[)\(slide(s?) (\d+)(?:[–\-](\d+))?\)"
)

# 3. Inline prose "slide N" (not preceded by [ or ( ): convert if N is in cumulative range.
INLINE_RE = re.compile(
    r"(?<![\[\(\w])slide (\d+)\b(?!\])"
)

# We only convert numbers in the cumulative range (>= 195, <= 360).
def in_range(n: int) -> bool:
    return 195 <= n <= 360

def fix_existing_link(m, prefix):
    plural = m.group(1)
    visible_old = m.group(2)
    path_old = m.group(3)
    page = int(m.group(4))
    # Extract the bare filename from path_old.
    fname_match = re.search(r"Session [^/)]+\.pdf$", path_old)
    if not fname_match:
        # Already URL-encoded? try decoding to find filename.
        fname_match = re.search(r"Session[^/)]+\.pdf$", path_old)
        if not fname_match:
            return m.group(0)
    fname = fname_match.group(0).replace("%20", " ")
    visible = f"slide{plural} {page}"
    if "–" in visible_old or "-" in visible_old:
        # Range case.
        # We don't know the second page from the existing link; keep the first page
        # link and rewrite visible to "slides {page}-?". The end is encoded in the
        # original visible text — try to recover it.
        end_match = re.search(r"[–\-](\d+)", visible_old)
        if end_match:
            end_cum = int(end_match.group(1))
            sess = session_for(end_cum)
            if sess:
                end_page = end_cum - sess[0]
                visible = f"slides {page}–{end_page}"
    return make_link(visible, prefix, fname, page)

def fix_bare_cite(m, prefix):
    plural = m.group(1)
    n_str = m.group(2)
    m_str = m.group(3)
    n = int(n_str)
    if not in_range(n):
        return m.group(0)
    sess = session_for(n)
    if not sess:
        return m.group(0)
    offset, fname, _ = sess
    page_n = n - offset
    if m_str:
        m_cum = int(m_str)
        sess2 = session_for(m_cum)
        if sess2 and sess2 == sess:
            page_m = m_cum - offset
            visible = f"slides {page_n}–{page_m}"
        else:
            visible = f"slides {page_n}–?"
    else:
        visible = f"slide {page_n}"
    return f"({make_link(visible, prefix, fname, page_n)})"

def fix_inline(m, prefix):
    n = int(m.group(1))
    if not in_range(n):
        return m.group(0)
    sess = session_for(n)
    if not sess:
        return m.group(0)
    offset, fname, _ = sess
    page = n - offset
    return make_link(f"slide {page}", prefix, fname, page)

def process_file(path: Path) -> int:
    """Return number of citations changed."""
    prefix = prefix_for(path)
    if not prefix:
        return 0
    text = path.read_text()
    orig = text

    # Skip YAML frontmatter.
    fm_match = re.match(r"^---\n.*?\n---\n", text, re.DOTALL)
    if fm_match:
        head = fm_match.group(0)
        body = text[len(head):]
    else:
        head = ""
        body = text

    body = EXISTING_LINK_RE.sub(lambda m: fix_existing_link(m, prefix), body)
    body = BARE_CITE_RE.sub(lambda m: fix_bare_cite(m, prefix), body)
    body = INLINE_RE.sub(lambda m: fix_inline(m, prefix), body)

    new = head + body
    if new != orig:
        path.write_text(new)
        # Count how many lines changed (rough metric).
        return sum(1 for a, b in zip(orig.splitlines(), new.splitlines()) if a != b)
    return 0

def main():
    files = collect_files()
    total = 0
    for f in files:
        n = process_file(f)
        if n:
            print(f"{f.relative_to(VAULT)}: {n} lines changed")
            total += n
    print(f"\nTotal: {total} lines changed across {len(files)} candidate files.")

if __name__ == "__main__":
    main()

